const JSON_URL = 'https://www.kalanera.gr/data/local-businesses.json';
const WEBHOOK_URL = 'https://n8n.vanlaar.cloud/webhook/local-businesses';
const MIN_ACTIVE = 50;
const MAX_DIFF = 2; // alert als verschil > 2 (dus >= 3)

function sheetStatus(row) {
  return String(row?.Status ?? row?.status ?? row?.STATUS ?? '').trim().toLowerCase();
}

function normalizeRows(payload) {
  if (Array.isArray(payload)) return payload;
  if (payload && Array.isArray(payload.rows)) return payload.rows;
  if (payload && Array.isArray(payload.data)) return payload.data;
  return [];
}

function countActive(payload) {
  return normalizeRows(payload).filter((r) => sheetStatus(r) === 'active').length;
}

async function getJson(url) {
  return this.helpers.httpRequest({
    method: 'GET',
    url,
    json: true,
    timeout: 30000,
  });
}

let jsonPayload;
let webhookPayload;
let jsonError = null;
let webhookError = null;

try {
  jsonPayload = await getJson.call(this, JSON_URL);
} catch (e) {
  jsonError = e?.message || String(e);
}

try {
  webhookPayload = await getJson.call(this, WEBHOOK_URL);
} catch (e) {
  webhookError = e?.message || String(e);
}

const jsonActive = jsonPayload != null ? countActive(jsonPayload) : 0;
const webhookActive = webhookPayload != null ? countActive(webhookPayload) : 0;
const diff = Math.abs(jsonActive - webhookActive);
const generatedAt = jsonPayload && typeof jsonPayload === 'object' && !Array.isArray(jsonPayload)
  ? (jsonPayload.generatedAt || null)
  : null;

const issues = [];
if (jsonError) issues.push(`JSON fetch mislukt: ${jsonError}`);
if (webhookError) issues.push(`Webhook fetch mislukt: ${webhookError}`);
if (!jsonError && jsonActive < MIN_ACTIVE) issues.push(`JSON te weinig Active-rijen: ${jsonActive} (min ${MIN_ACTIVE})`);
if (!webhookError && webhookActive < MIN_ACTIVE) issues.push(`Webhook te weinig Active-rijen: ${webhookActive} (min ${MIN_ACTIVE})`);
if (!jsonError && !webhookError && diff > MAX_DIFF) {
  issues.push(`JSON (${jsonActive}) en webhook (${webhookActive}) lopen uit sync (verschil ${diff})`);
}
if (!jsonError && jsonActive === 0 && webhookActive > 0) {
  issues.push('JSON leeg/ongeldig terwijl webhook data heeft — deploy/publish vergeten?');
}

const ok = issues.length === 0;
const subject = ok
  ? '[kalanera] JSON/webhook OK (wekelijkse check)'
  : '[kalanera] ALERT: JSON vs webhook uit sync';

const lines = [
  'Kalanera — wekelijkse vergelijking statische JSON vs n8n-webhook',
  `Tijd (UTC): ${new Date().toISOString()}`,
  '',
  `Statische JSON: ${jsonActive} Active-rijen${generatedAt ? `, generatedAt ${generatedAt}` : ''}`,
  `Webhook fallback: ${webhookActive} Active-rijen`,
  `Verschil: ${diff}`,
  '',
];

if (ok) {
  lines.push('Status: OK — geen actie nodig.');
} else {
  lines.push('Status: PROBLEEM');
  lines.push('');
  issues.forEach((msg) => lines.push(`- ${msg}`));
  lines.push('');
  lines.push('Actie: publish-workflow draaien, JSON op server controleren, of Sheet vs deploy vergelijken.');
}

function escHtml(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}
function toBodyHtml(lines) {
  return `<!DOCTYPE html><html><body style="font-family:system-ui,sans-serif;font-size:14px;line-height:1.45;max-width:42em"><pre style="white-space:pre-wrap;margin:0">${escHtml(lines.join('\n'))}</pre></body></html>`;
}
const body = lines.join('\n');

return [{
  json: {
    ok,
    alert: !ok,
    jsonActive,
    webhookActive,
    diff,
    generatedAt,
    issues,
    subject,
    body,
    bodyHtml: toBodyHtml(lines),
  },
}];
